DELETE FROM games WHERE id LIKE 'game-%';
INSERT INTO games (id, title, description, cover_image, release_date, genre, platform, press_score, user_score, category, created_at, updated_at) VALUES
('game-001', 'The Legend of Zelda: Ocarina of Time', 'Considerado por muchos como el mejor juego de todos los tiempos. Revolucionó el género de aventuras con su sistema Z-targeting y mundo 3D.', 'https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fhowlongtobeat.com%2Fgames%2F10035_The_Legend_of_Zelda_Ocarina_of_Time.png&f=1&nofb=1&ipt=21c8b8288d2c87b3964744b84d02436efb6a8649df653df29066e73bb603e39c', '1998-11-21', ARRAY['Aventura', 'Acción', 'RPG'], ARRAY['N64'], 99, 94, 'Top de la historia', NOW(), NOW()),
('game-002', 'Tetris', 'El puzzle más icónico de la historia. Simple, adictivo y atemporal. Creó el género de los juegos de puzzle.', 'https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fwww.mobygames.com%2Fimages%2Fcovers%2Fl%2F16097-tetris-nes-front-cover.jpg&f=1&nofb=1&ipt=c168e8a690a5689f39c73f8c1e7b1a0e24c7fbbd2eca1b47687a9e189155ec51', '1984-06-06', ARRAY['Puzzle', 'Arcade'], ARRAY['NES', 'Game Boy', 'PC'], 96, 88, 'Top de la historia', NOW(), NOW()),
('game-003', 'Super Mario Bros.', 'El juego que salvó la industria de los videojuegos tras la crisis de 1983. Definió el género de plataformas.', 'https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fpre00.deviantart.net%2Feef9%2Fth%2Fpre%2Fi%2F2014%2F172%2F3%2Fb%2Fsuper_mario_bros_nes_cover_by_perrito_gatito-d7ndqiw.png&f=1&nofb=1&ipt=a3d179ebf6f6f83665392e2b814bd3756eaf1748370c5d6e1a4706a1166de173', '1985-09-13', ARRAY['Plataformas', 'Aventura'], ARRAY['NES'], 94, 90, 'Top de la historia', NOW(), NOW()),
('game-004', 'The Legend of Zelda: Breath of the Wild', 'Revolucionó los juegos de mundo abierto con su libertad sin precedentes y física emergente.', 'https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fwallpapers.com%2Fimages%2Fhd%2Fultra-hd-breath-of-the-wild-game-cover-ny16mxrpbl6lo96p.jpg&f=1&nofb=1&ipt=512c85188805ff23ce02abb40a8d9233f456c884698d102fae8eec632732bd92', '2017-03-03', ARRAY['Aventura', 'Acción', 'Mundo Abierto'], ARRAY['Switch', 'Wii U'], 98, 95, 'Top de la historia', NOW(), NOW()),
('game-005', 'Red Dead Redemption 2', 'Una obra maestra narrativa con el mundo abierto más detallado jamás creado. La culminación del western interactivo.', 'https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fassets.vg247.com%2Fcurrent%2F2018%2F05%2Fred_dead_redemption_2_cover_art_1.jpg&f=1&nofb=1&ipt=20239d564637f6e7efe9c312f9cf24f8e14b56744f5cb4de00b4eb2bef262e6c', '2018-10-26', ARRAY['Acción', 'Aventura', 'Mundo Abierto'], ARRAY['PS4', 'Xbox One', 'PC'], 97, 88, 'Top de la historia', NOW(), NOW()),
('game-006', 'The Witcher 3: Wild Hunt', 'El estándar de oro de los RPG de mundo abierto. Narrativa profunda, mundo vasto y personajes memorables.', 'https://external-content.duckduckgo.com/iu/?u=http%3A%2F%2Fwww.mobygames.com%2Fimages%2Fcovers%2Fl%2F392214-the-witcher-3-wild-hunt-xbox-one-front-cover.png&f=1&nofb=1&ipt=d5e03cb618686359056f8435b344c05fdb7ef7fa441e707c8fc353383d5c2f7f', '2015-05-19', ARRAY['RPG', 'Aventura', 'Mundo Abierto'], ARRAY['PC', 'PS4', 'Xbox One', 'Switch'], 92, 93, 'Top de la historia', NOW(), NOW()),
('game-007', 'Minecraft', 'El juego más vendido de la historia. Creatividad infinita en un mundo de bloques que ha capturado a generaciones.', 'https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fimages-wixmp-ed30a86b8c4ca887773594c2.wixmp.com%2Ff%2F38eb60f7-015f-4e9a-a98c-0f81cb883d0f%2Fdg3rj58-5cf5800a-6f42-42a4-9a1d-cc5d619c5d81.jpg%3Ftoken%3DeyJ0eXAiOiJKV1QiLCJhbGciOiJIUzI1NiJ9..4u6Fga8fmpD-s6n7hoPLqvcRLEeOTo08DfKfMC0_Fl8&f=1&nofb=1&ipt=0f85415dd431b09d8aeb2120a20f8d3c1323341bfa9f588a1096c27c829aabb8', '2011-11-18', ARRAY['Sandbox', 'Supervivencia', 'Aventura'], ARRAY['PC', 'PS4', 'Xbox One', 'Switch', 'Mobile'], 93, 89, 'Top de la historia', NOW(), NOW()),
('game-008', 'Grand Theft Auto V', 'El juego de mundo abierto más influyente de la última década. Sátira social, humor negro y libertad total.', 'https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fwww.gtabase.com%2Figallery%2F501-600%2FGTA_V_Official_Cover_Art-524-1920.jpg&f=1&nofb=1&ipt=9ffcaa129db28c36da19c39564f0660ad2012b631b2eff106896627cdffb9324', '2013-09-17', ARRAY['Acción', 'Aventura', 'Mundo Abierto'], ARRAY['PS3', 'Xbox 360', 'PS4', 'Xbox One', 'PC', 'PS5', 'Xbox Series X|S'], 97, 86, 'Top de la historia', NOW(), NOW()),
('game-009', 'The Last of Us', 'Una experiencia narrativa sin precedentes que elevó el medio al nivel del cine. Emocional, brutal y hermoso.', 'https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Ftse1.mm.bing.net%2Fth%2Fid%2FOIP.1j3CztzmArPjY4gwr02xFwHaLH%3Fpid%3DApi&f=1&ipt=821c58842f4df40674e670bed7f931e956e28fb761b659c017f60061f05e3c1b', '2013-06-14', ARRAY['Acción', 'Aventura', 'Survival Horror'], ARRAY['PS3', 'PS4'], 95, 92, 'Top de la historia', NOW(), NOW()),
('game-010', 'Half-Life 2', 'Revolucionó los FPS con su motor de física, narrativa integrada y diseño de niveles sin precedentes.', 'https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Ftse1.mm.bing.net%2Fth%2Fid%2FOIP.IoNfk8dPBT-yHsnGD1QZEQHaLH%3Fpid%3DApi&f=1&ipt=5d9df6679a26433e4a7dcec9f3ac23b4e9486a03a8cc200ba3aa5015d82f678b', '2004-11-16', ARRAY['Shooter', 'FPS', 'Ciencia Ficción'], ARRAY['PC'], 96, 90, 'Top de la historia', NOW(), NOW()),
